class {{nama_class}}:
    """Simple mock object. Records all attribute access and method calls.
    Usage:
        m = MockObject(name='test')
        m.some_method(1, 2)
        assert m.some_method.calls == [(1, 2)]
    """
    def __init__(self, name='mock', **attrs):
        self._name = name
        self._calls = {}
        self._attrs = dict(attrs)
        self._return_values = {}

    def __getattr__(self, name):
        if name.startswith('_'):
            raise AttributeError(name)
        if name in self._attrs:
            return self._attrs[name]
        def _mock_method(*args, **kwargs):
            if name not in self._calls:
                self._calls[name] = []
            self._calls[name].append((args, kwargs))
            return self._return_values.get(name)
        _mock_method.__name__ = name
        return _mock_method

    def set_return(self, method_name, value):
        """Set return value for a mock method."""
        self._return_values[method_name] = value
        return self

    def call_count(self, method_name):
        """How many times a method was called."""
        return len(self._calls.get(method_name, []))

    @property
    def calls(self):
        return dict(self._calls)

    def reset(self):
        self._calls.clear()

class {{nama_class}}:
    """Generate realistic test fixture data. Deterministic with seed."""
    FIRST_NAMES = ['Alice', 'Bob', 'Charlie', 'Diana', 'Eve', 'Frank', 'Grace', 'Hank', 'Ivy', 'Jack']
    LAST_NAMES = ['Smith', 'Johnson', 'Brown', 'Davis', 'Wilson', 'Moore', 'Taylor', 'Anderson', 'Thomas', 'White']
    DOMAINS = ['example.com', 'test.org', 'demo.net', 'sample.io']
    STREETS = ['Main St', 'Oak Ave', 'Elm St', 'Pine Rd', 'Cedar Ln', 'Maple Dr']
    CITIES = ['Jakarta', 'Bandung', 'Surabaya', 'Medan', 'Semarang', 'Makassar']

    def __init__(self, seed={{seed}}):
        self._rng = random.Random(seed)

    def _pick(self, lst):
        return self._rng.choice(lst)

    def user(self):
        first = self._pick(self.FIRST_NAMES)
        last = self._pick(self.LAST_NAMES)
        domain = self._pick(self.DOMAINS)
        return {
            'id': self._rng.randint(1, 99999),
            'first_name': first,
            'last_name': last,
            'email': (first + '.' + last + '@' + domain).lower(),
            'age': self._rng.randint(18, 70),
        }

    def product(self):
        adjectives = ['Premium', 'Basic', 'Pro', 'Ultra', 'Mini', 'Mega']
        nouns = ['Widget', 'Gadget', 'Tool', 'Device', 'Kit', 'Pack']
        return {
            'id': self._rng.randint(1, 99999),
            'name': self._pick(adjectives) + ' ' + self._pick(nouns),
            'price': round(self._rng.uniform(5, 500), 2),
            'stock': self._rng.randint(0, 1000),
        }

    def order(self):
        return {
            'id': self._rng.randint(1, 99999),
            'user_id': self._rng.randint(1, 99999),
            'total': round(self._rng.uniform(10, 2000), 2),
            'status': self._pick(['pending', 'paid', 'shipped', 'delivered', 'cancelled']),
            'items_count': self._rng.randint(1, 10),
        }

    def address(self):
        return {
            'street': str(self._rng.randint(1, 200)) + ' ' + self._pick(self.STREETS),
            'city': self._pick(self.CITIES),
            'postal_code': str(self._rng.randint(10000, 99999)),
            'country': 'Indonesia',
        }

    def batch(self, generator_func, count):
        """Generate multiple records. generator_func: self.user, self.product, etc."""
        return [generator_func() for _ in range(count)]

