        raise AssertionError(msg or 'Expected %s ≈ %s (tolerance=%s), got diff=%s' % (a, b, tolerance, abs(a - b)))


def {{prefix}}subset(sub, superset, msg=None):
    """Assert sub is a subset of superset (works for lists and dicts)."""
    if isinstance(sub, dict) and isinstance(superset, dict):
        for k, v in sub.items():
            if k not in superset:
                raise AssertionError(msg or 'Key %r missing from dict' % k)
