def {{prefix}}type(obj, expected_type, msg=None):
    """Assert obj is instance of expected_type."""
    if not isinstance(obj, expected_type):
        raise AssertionError(msg or 'Expected type %s, got %s' % (expected_type.__name__, type(obj).__name__))


def {{prefix}}raises(exception_class, func, *args, **kwargs):
    """Assert that func(*args, **kwargs) raises the expected exception.
    Returns the exception instance for further inspection.
    """
    try:
        func(*args, **kwargs)
    except exception_class as exc:
        return exc
    except Exception as exc:
        raise AssertionError('Expected %s but got %s: %s' % (exception_class.__name__, type(exc).__name__, exc))
    raise AssertionError('Expected %s but no exception was raised' % exception_class.__name__)


def {{prefix}}length(collection, expected, msg=None):
