        raise AssertionError(msg or 'Expected length %d, got %d' % (expected, actual))

class {{nama_class}}:
    """Generate random test data using only stdlib."""
    def __init__(self, seed=None):
        self._rng = random.Random(seed)

    def name(self):
        first = ['Alice', 'Bob', 'Charlie', 'Diana', 'Eve', 'Frank', 'Grace', 'Hugo', 'Iris', 'Jack',
                 'Kara', 'Leo', 'Mia', 'Noah', 'Olga', 'Paul', 'Quinn', 'Rosa', 'Sam', 'Tina']
        last = ['Adams', 'Brown', 'Clark', 'Davis', 'Evans', 'Fisher', 'Garcia', 'Harris', 'Ivanov', 'Jones']
        return self._rng.choice(first) + ' ' + self._rng.choice(last)

    def email(self):
        domains = ['test.com', 'example.org', 'demo.io', 'sample.net']
        word = ''.join(self._rng.choices(string.ascii_lowercase, k=8))
        return word + '@' + self._rng.choice(domains)

    def phone(self, country_code='+62'):
        digits = ''.join(self._rng.choices(string.digits, k=10))
        return country_code + digits

    def uuid(self):
        return str(uuid.UUID(int=self._rng.getrandbits(128), version=4))

    def date(self, start_year=2000, end_year=2025):
        start = datetime.date(start_year, 1, 1)
        end = datetime.date(end_year, 12, 31)
        delta = (end - start).days
        random_days = self._rng.randint(0, delta)
        return (start + datetime.timedelta(days=random_days)).isoformat()

    def text(self, words=10):
        word_list = ['lorem', 'ipsum', 'dolor', 'sit', 'amet', 'consectetur', 'adipiscing',
                     'elit', 'sed', 'do', 'eiusmod', 'tempor', 'incididunt', 'ut', 'labore']
        return ' '.join(self._rng.choices(word_list, k=words))

    def integer(self, low=0, high=10000):
        return self._rng.randint(low, high)

    def float_val(self, low=0.0, high=1000.0, decimals=2):
        return round(self._rng.uniform(low, high), decimals)

    def boolean(self, true_rate=0.5):
        return self._rng.random() < true_rate

    def choice(self, options):
        return self._rng.choice(options)

class {{nama_class}}:
    """Property-based testing helper. Generate random inputs and verify invariants.
    Usage:
        pt = PropertyTester()
        pt.check(lambda x: abs(x) >= 0, pt.gen_int, 'abs always positive')
    """
    def __init__(self, seed=None):
        self._rng = random.Random(seed)

    def gen_int(self, low=-1000, high=1000):
        return lambda: self._rng.randint(low, high)

    def gen_float(self, low=-1000.0, high=1000.0):
        return lambda: self._rng.uniform(low, high)

    def gen_string(self, min_len=0, max_len=50):
        def _gen():
            length = self._rng.randint(min_len, max_len)
            chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789 '
            return ''.join(self._rng.choices(chars, k=length))
        return _gen

    def gen_list(self, element_gen, min_len=0, max_len=20):
        def _gen():
            length = self._rng.randint(min_len, max_len)
            return [element_gen() for _ in range(length)]
        return _gen

    def gen_choice(self, options):
        return lambda: self._rng.choice(options)

    def check(self, predicate, generator, label='property', cases={{default_cases}}):
        """Run predicate(generator()) N times. Raises on first failure with counterexample."""
        failures = []
        for i in range(cases):
            value = generator()
            try:
                result = predicate(value)
            except Exception as exc:
                failures.append((i, value, str(exc)))
                break
            if not result:
                failures.append((i, value, 'predicate returned False'))
                break
        if failures:
            idx, val, msg = failures[0]
            raise AssertionError(
                'Property "%s" failed at case #%d: input=%r, reason=%s' % (label, idx, val, msg)
            )
        return True

    def check_no_exception(self, func, generator, label='no_exception', cases={{default_cases}}):
        """Run func(generator()) N times, assert no exception raised."""
        for i in range(cases):
            value = generator()
            try:
                func(value)
            except Exception as exc:
                raise AssertionError(
                    'Property "%s" raised %s at case #%d: input=%r' % (label, type(exc).__name__, i, value)
                )
        return True

class {{nama_class}}:
    """Auto-discover and run test files. Stdlib unittest compatible."""
    def __init__(self, test_dir='.', pattern='{{pattern}}'):
        self.test_dir = os.path.abspath(test_dir)
        self.pattern = pattern

    def discover(self):
        """Discover test modules. Returns unittest.TestSuite."""
        loader = unittest.TestLoader()
        return loader.discover(self.test_dir, pattern=self.pattern)

    def run(self, suite=None, verbosity=1):
        """Run test suite. Returns dict with results summary."""
        if suite is None:
            suite = self.discover()
        stream = io.StringIO()
        runner = unittest.TextTestRunner(stream=stream, verbosity=verbosity)
        result = runner.run(suite)
        return {
            'tests_run': result.testsRun,
            'failures': len(result.failures),
            'errors': len(result.errors),
            'skipped': len(result.skipped),
            'successful': result.testsRun - len(result.failures) - len(result.errors) - len(result.skipped),
            'output': stream.getvalue(),
            'passed': result.wasSuccessful(),
        }

    def run_quick(self):
        """Quick summary: run tests, return pass/fail count."""
        result = self.run(verbosity=0)
        return 'PASS' if result['passed'] else 'FAIL (%d failures, %d errors)' % (result['failures'], result['errors'])
